const pedidosData = $('Obtener pedidos').all();
const clientesData = $('Obtener clientes').all();
const cartaData = $('Obtener Carta').all();
const memoriaData = $('Obtener Memoria').all();

let textoPedidos = "No hay pedidos activos";

if (pedidosData.length > 0 && pedidosData[0].json && Object.keys(pedidosData[0].json).length > 0)
{
  textoPedidos = pedidosData.map(item => `fila: ${item.json.row_number} |  fecha: ${item.json.fecha} | cliente: ${item.json.cliente} | cantidad: ${item.json.cantidad} | tipo_pedido: ${item.json.tipo_pedido} | Plato: ${item.json.plato } | detalles: ${item.json.detalles} | hora_entrega: ${item.json.hora_entrega} | pago_completo: ${item.json.pago_completo} | se_entrego_pedido: ${item.json.se_entrego_pedido} | entrego_platos: ${item.json.entrego_platos} | es_reserva: ${item.json.es_reserva || false}`).join('\n');
}

let textoClientes = "No hay clientes registrados aún."
if (clientesData.length > 0 && clientesData[0].json && Object.keys(clientesData[0].json).length > 0)
{
  textoClientes = clientesData.map(item => `Cliente: ${item.json.Cliente} | Preferencias: ${item.json.Preferencias}`).join('\n');
}

let textoCarta = "No hay carta registrada.";
if(cartaData.length > 0 && cartaData[0].json && Object.keys(cartaData[0].json).length > 0)
{
  textoCarta = cartaData.map(item => `Fecha: ${item.json.Fecha} | Turno: ${item.json.Turno} | Plato: ${item.json.Plato} | Tipo: ${item.json.Tipo} | Incluido en Menú: ${item.json.Incluido_en_Menu} | Precio Unitario: S/.${item.json.Precio || 0}`).join('\n');
}

let textoMemoria = "No hay ninguna conversación a medias. Trata este audio como una instrucción completamente nueva.";
if (memoriaData.length > 0 && memoriaData[0].json.Pregunta_IA)
{
  textoMemoria = `ATENCION - HILO DE CONVERSACION ACTIVO: La ultima vez que hablaste con el mesero, el pedido quedo incompleto. Tú (la IA) le preguntaste esto: "${memoriaData[0].json.Pregunta_IA}". El contexto de lo que el mesero intentaba pedir era esto: "${memoriaData[0].json.Borrador_Contexto}". EL AUDIO ACTUAL ES LA RESPUESTA DEL MESERO A TU PREGUNTA. Usalo para completar la accion original.`;
}


const audioBinario = $("Webhook_voz").first().binary;

return [{
  json: {
    historial_pedidos: textoPedidos,
    lista_clientes: textoClientes,
    carta_del_dia: textoCarta,
    memoria_activa: textoMemoria
  },
  binary: audioBinario
}];

const intencion = $input.first()?.json?.intencion;
let audioBase64 = null;

// MAGIA DE N8N: Extraemos el archivo real desde el disco (filesystem) hacia la memoria
try {
  // Verificamos si el archivo se llama 'data'
  if ($input.first()?.binary?.data) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    audioBase64 = buffer.toString('base64');
  } 
  // O si el archivo se llama 'audio'
  else if ($input.first()?.binary?.audio) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'audio');
    audioBase64 = buffer.toString('base64');
  }
} catch (error) {
  console.error("No se pudo leer el archivo binario:", error);
}

// Construimos la respuesta
if (intencion !== "eliminar") {
  return [{
    json: {
      "intencion": intencion,
      "audio_base64": audioBase64
    }
  }];
} else {
  return [{
    json: {
      "estado": "requiere_confirmacion",
      "accion": "eliminar",
      "datos": {
        "fila": $('json_gemini').first().json.eliminacion.row_number,
        "mensaje_popup": $('Code in JavaScript').first().json.guion
      },
      "audio_base64": audioBase64
    }
  }];
}

return {
  json: {
    intencion: "respuesta",
    guion: "Pedido eliminado correctamente de la lista"
  }
};

